//
import { EXPANDABLE_CLASSNAME } from '../../legend-constants';
import { Registry } from '../../../core/zc-registry';

/**
 *
 * @param chart
 * @return {Legend Event options}
 */
function _legendExpandableEventArguments(chart, id) {
    let legendInstance = chart.legends.get(id),
        { component, meta, element } = legendInstance,
        { globalFont } = meta,
        //
        trackerElement = getTrackerElement(element),
        expandableParser,
        enabled = legendInstance.enabled;

    if (enabled) {
        expandableParser = component.encode.children[2]._parser; //TODO: code clean
        enabled = expandableParser.show;
    }
    let config = expandableParser.config || {};

    return { enabled, trackerElement, config, globalFont, expandableParser, legendInstance, markParser: component && component.encode && component.encode.children[2]};
}

/**
 * Returns tracker element
 * @param  {D3Selectiion} container
 * @return {D3Selectiion}
 */
function getTrackerElement(container) {
    return container.selectAll(`div.${EXPANDABLE_CLASSNAME}`);
}

export { _legendExpandableEventArguments };
Registry.setComponent('_legendExpandableEventArguments', _legendExpandableEventArguments);
